oxy_webhelp_navlinks = {"okta_idp-d27243e45739":{"topics":[{"title":"Introduction to Okta protection","href":"okta\/okta_key_features_protection.html","menu":{"hasChildren":false},"tocID":"tocId-d27243e45752","next":"tocId-d27243e45752"},{"title":"Plan your Okta IdP protection","shortdesc":"<p class=\"shortdesc\">Before integrating Okta IdP with <span class=\"ph\">RSC<\/span>, you must meet certain         requirements to start protecting your critical Okta objects.<\/p>","href":"okta\/plan_okta_idp_protection.html","attributes":{"data-id":"plan_okta_idp_protection"},"menu":{"hasChildren":false},"tocID":"plan_okta_idp_protection-d27243e45777","next":"plan_okta_idp_protection-d27243e45777"},{"title":"Evaluate Okta configuration options","shortdesc":"<p class=\"shortdesc\">You can add Okta tenants to <span class=\"ph\">RSC<\/span> using the Identity Resilience         inventory, Data Protection inventory, or Settings menu.<\/p>","href":"okta\/evaluate_okta_configuration_options.html","attributes":{"data-id":"evaluate_okta_configuration_options"},"menu":{"hasChildren":false},"tocID":"evaluate_okta_configuration_options-d27243e45828","topics":[]},{"title":"Configure Okta IdP","shortdesc":"<p class=\"shortdesc\">Configure your Okta Identity Provider by adding Okta tenants to <span class=\"ph\">RSC<\/span>         and perform other maintenance operations, such as editing and removing the Okta         tenants.<\/p>","href":"okta\/configure_okta_idp.html","attributes":{"data-id":"configure_okta_idp"},"menu":{"hasChildren":false},"tocID":"configure_okta_idp-d27243e45842","next":"configure_okta_idp-d27243e45842"},{"title":"Manage protection for Okta IdP","shortdesc":"<p class=\"shortdesc\">You can use SLA Domains to apply data protection and management policies to Okta         tenants for optimal protection.<\/p>","href":"okta\/manage_protection_okta_idp.html","attributes":{"data-id":"manage_protection_okta_idp"},"menu":{"hasChildren":false},"tocID":"manage_protection_okta_idp-d27243e45895","next":"manage_protection_okta_idp-d27243e45895"},{"title":"Recover Okta objects","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides protection for critical Okta objects. You can assign an         SLA Domain to your Okta tenant to begin the automated backups. You can recover the required         Okta objects using the automated backups or on-demand snapshots.<\/p>","href":"okta\/recover_okta_objects.html","attributes":{"data-id":"recover_okta_objects"},"menu":{"hasChildren":false},"tocID":"recover_okta_objects-d27243e45942","next":"recover_okta_objects-d27243e45942"},{"title":"Manage Okta tenants","shortdesc":"<p class=\"shortdesc\">Viewing and analyzing detailed information about your protected Okta IdP from the         Inventory page enables you to make informed decisions. Key aspects include viewing tenants,         checking protection status, reviewing detailed object attributes, browsing the snapshot         calendar, viewing events log for audit and compliance, and performing maintenance such as         deleting snapshots.<\/p>","href":"okta\/manage_okta_tenants.html","attributes":{"data-id":"manage_okta_tenants"},"menu":{"hasChildren":false},"tocID":"manage_okta_tenants-d27243e46007","next":"manage_okta_tenants-d27243e46007"}]}};